           <span className="text-[9px] font-bold tracking-[0.2em] text-white/30 mb-1 uppercase font-sans">Strategy</span>
           <div className="flex gap-1.5 mt-2">
             {[...Array(3)].map((_, i) => (
               <div key={i} className={`w-1 h-1 rounded-full ${i === activeStep ? 'bg-white scale-125' : 'bg-white/10'} transition-all duration-500`}></div>
             ))}
           </div>
        </div>

        <div className="absolute inset-0 rounded-full border border-white/[0.05]"></div>

        {steps.map((step, idx) => {
          const angle = (idx * (360 / steps.length)) - 90;
          const isActive = activeStep === idx;
          const rotationAngle = angle + (activeStep * -120);

          return (
            <div 
              key={step.id}
              className="absolute top-1/2 left-1/2 w-full h-full transition-transform duration-700 ease-[cubic-bezier(0.2,1,0.3,1)] z-30 pointer-events-none"
              style={{ transform: `translate3d(-50%, -50%, 0) rotate(${rotationAngle}deg)` }}
            >
              <button 
                onClick={() => handleStepChange(idx)}
                className={`absolute top-0 left-1/2 -translate-x-1/2 -translate-y-1/2 pointer-events-auto transition-all duration-700 ${
                  isActive ? 'scale-110' : 'scale-90 opacity-40 hover:opacity-100 hover:scale-100'
                }`}
              >
                <div 
                  className="flex flex-col items-center gap-2"
                  style={{ transform: `rotate(${-rotationAngle}deg)` }}
                >
                  <div className={`w-12 h-12 md:w-14 md:h-14 glass rounded-2xl border flex items-center justify-center relative transition-all duration-500 bg-black/60 ${
                    isActive ? 'border-white/40 shadow-xl' : 'border-white/10 hover:border-white/30'
                  }`}>
                    <div className={`${isActive ? 'text-white' : 'text-white/40'}`}>
