          <div className="relative z-10">
            <div className="flex items-center gap-3 mb-6">
              <span className="text-[10px] font-bold tracking-[0.2em] text-white/30 uppercase font-sans">
                {steps[activeStep].label}
              </span>
              <div className="h-[1px] flex-1 bg-white/[0.03]"></div>
            </div>

            <h3 className="text-3xl md:text-4xl font-bold tracking-tight text-white mb-6 font-display">
