import React, { useEffect, useState, useRef } from 'react';
import { View } from '../types';

interface CustomCursorProps {
  currentView?: View;
}

const CustomCursor: React.FC<CustomCursorProps> = ({ currentView }) => {
  const dotRef = useRef<HTMLDivElement>(null);
  const ringRef = useRef<HTMLDivElement>(null);
  const [hoverType, setHoverType] = useState<'none' | 'ui' | 'project'>('none');
  const [isVisible, setIsVisible] = useState(false);

  const isDetail = currentView === 'project-detail';

  useEffect(() => {
    const onMouseMove = (e: MouseEvent) => {
      if (!isVisible) setIsVisible(true);

      const { clientX, clientY } = e;

      if (dotRef.current) {
        dotRef.current.style.transform = `translate3d(${clientX}px, ${clientY}px, 0)`;
      }

      if (ringRef.current) {
        ringRef.current.style.transform = `translate3d(${clientX}px, ${clientY}px, 0)`;
      }

      // Detect interaction type
      const target = e.target as HTMLElement;
      if (target.closest('[data-cursor="project"]')) {
        setHoverType('project');
      } else if (target.closest('button, a, .cursor-pointer, input')) {
        setHoverType('ui');
      } else {
        setHoverType('none');
      }
    };

    const onMouseLeave = () => setIsVisible(false);
    const onMouseEnter = () => setIsVisible(true);

    window.addEventListener('mousemove', onMouseMove);
    document.addEventListener('mouseleave', onMouseLeave);
    document.addEventListener('mouseenter', onMouseEnter);

    return () => {
      window.removeEventListener('mousemove', onMouseMove);
      document.removeEventListener('mouseleave', onMouseLeave);
      document.removeEventListener('mouseenter', onMouseEnter);
    };
  }, [isVisible]);

  const getRingStyles = () => {
    switch (hoverType) {
      case 'project':
        // Use orange only if it's the detail view transitioning to another project, or silver if on home
        const accentClass = isDetail 
          ? 'bg-orange-600/10 border-orange-500/50 shadow-[0_0_25px_rgba(234,88,12,0.2)]' 
          : 'bg-white/10 border-white/50 shadow-[0_0_25px_rgba(255,255,255,0.1)]';
        return `w-24 h-24 -ml-12 -mt-12 scale-100 ${accentClass}`;
      case 'ui':
        return 'w-16 h-16 -ml-8 -mt-8 bg-white/5 border-white/40 scale-100';
      default:
        return 'w-8 h-8 -ml-4 -mt-4 bg-transparent border-white/20 scale-100';
    }
  };

  return (
    <div className={`fixed inset-0 pointer-events-none z-[9999] transition-opacity duration-300 ${isVisible ? 'opacity-100' : 'opacity-0'} hidden md:block`}>
      {/* Precision Dot */}
      <div 
        ref={dotRef}
        className="fixed top-0 left-0 w-1.5 h-1.5 bg-white rounded-full -ml-0.75 -mt-0.75 will-change-transform"
      />
      {/* Fluid Ring */}
      <div 
        ref={ringRef}
        className={`fixed top-0 left-0 border rounded-full transition-all duration-300 ease-out will-change-transform backdrop-blur-[2px] flex items-center justify-center ${getRingStyles()}`}
      >
        <span className={`text-[9px] font-black tracking-[0.3em] text-white transition-opacity duration-300 ${hoverType === 'project' ? 'opacity-100' : 'opacity-0'}`}>
          SELECT
        </span>
      </div>
    </div>
  );
};

export default CustomCursor;

