const NorthStarCard: React.FC<{ label: string; description: string }> = ({ label, description }) => {
  const containerRef = useRef<HTMLDivElement>(null);
  const [mousePos, setMousePos] = useState({ x: 0, y: 0 });
  const [isHovered, setIsHovered] = useState(false);

  const handleMouseMove = (e: React.MouseEvent) => {
    if (!containerRef.current) return;
    const rect = containerRef.current.getBoundingClientRect();
    setMousePos({ x: e.clientX - rect.left, y: e.clientY - rect.top });
  };

  return (
    <div 
      ref={containerRef}
      onMouseMove={handleMouseMove}
      onMouseEnter={() => setIsHovered(true)}
      onMouseLeave={() => setIsHovered(false)}
      className="group relative w-full max-w-3xl mx-auto glass p-10 md:p-16 rounded-[3rem] border border-white/10 transition-all duration-[800ms] hover:border-orange-500/30 shadow-2xl overflow-hidden cursor-default perspective-1000 bg-white/[0.02]"
      style={{
        transform: isHovered 
          ? `perspective(1000px) rotateX(${(mousePos.y / 300 - 1) * -2}deg) rotateY(${(mousePos.x / 450 - 1) * 2}deg)` 
          : 'none'
      }}
    >
      {/* Interactive Light Sweep */}
      <div 
        className="absolute inset-0 pointer-events-none opacity-0 group-hover:opacity-100 transition-opacity duration-500"
        style={{
          background: `radial-gradient(circle at ${mousePos.x}px ${mousePos.y}px, rgba(249, 115, 22, 0.08) 0%, transparent 60%)`
        }}
      />

      <div className="relative z-10 flex flex-col items-center text-center">
        <div className="flex items-center gap-3 mb-8">
           <div className="w-1.5 h-1.5 rounded-full bg-orange-500 shadow-[0_0_10px_rgba(249,115,22,0.8)]"></div>
