        })}
      </div>
      <style>{`.vertical-text { writing-mode: vertical-rl; } .animate-spin-slow { animation: spin 25s linear infinite; } @keyframes spin { from { transform: rotate(0deg); } to { transform: rotate(360deg); } }`}</style>
