      style={{
        transform: isHovered 
          ? `perspective(2000px) rotateX(${(mousePos.y / 200 - 1) * -2}deg) rotateY(${(mousePos.x / 350 - 1) * 2}deg)` 
          : 'none'
      }}
    >
      {/* Subtle Inner Glow */}
