          const angle = (idx * (360 / steps.length)) - 90;
          const isActive = activeStep === idx;
          const rotationAngle = angle + (activeStep * -120);
          return (
            <div key={step.id} className="absolute top-1/2 left-1/2 w-full h-full transition-transform duration-[800ms] ease-[cubic-bezier(0.2,1,0.3,1)] z-30 pointer-events-none" style={{ transform: `translate3d(-50%, -50%, 0) rotate(${rotationAngle}deg)` }}>
              <button onClick={() => handleStepChange(idx)} className={`absolute top-0 left-1/2 -translate-x-1/2 -translate-y-1/2 pointer-events-auto transition-all duration-700 ${isActive ? 'scale-110' : 'scale-90 opacity-60 hover:opacity-100 hover:scale-100'}`}>
                <div className="flex flex-col items-center gap-2" style={{ transform: `rotate(${-rotationAngle}deg)` }}>
                  <div className={`w-14 h-14 rounded-2xl border flex items-center justify-center relative transition-all duration-500 bg-white/[0.05] backdrop-blur-xl ${isActive ? 'border-orange-500/60 shadow-[0_0_30px_rgba(249,115,22,0.3)]' : 'border-white/20 hover:border-white/40'}`}>
                    <div className={`${isActive ? 'text-orange-500 scale-110' : 'text-white/60'}`}>{step.icon}</div>
                  </div>
                </div>
              </button>
            </div>
          );
        })}
      </div>
      <div className="flex-1 w-full relative">
        <div className={`p-10 md:p-14 rounded-[4rem] border border-white/20 relative overflow-hidden transition-all duration-500 shadow-2xl min-h-[350px] flex flex-col justify-center bg-white/[0.03] backdrop-blur-[100px] ${isRotating ? 'opacity-0 translate-y-4 blur-xl' : 'opacity-100 translate-y-0 blur-none'}`}>
          <div className="relative z-10 text-left">
            <div className="flex items-center gap-4 mb-8">
              <span className="text-[11px] font-black tracking-[0.3em] text-orange-500 uppercase font-sans">{steps[activeStep].phase}</span>
              <div className="h-[1px] flex-1 bg-white/[0.15]"></div>
            </div>
            <h3 className="text-3xl md:text-4xl font-bold tracking-tight text-white mb-6 font-display">{steps[activeStep].title}</h3>
            <p className="text-lg md:text-xl text-white/80 font-light italic leading-relaxed tracking-tight">"{steps[activeStep].content}"</p>
          </div>
          {/* Glass Inner Shine */}
          <div className="absolute top-0 left-0 right-0 h-1 bg-gradient-to-r from-transparent via-white/10 to-transparent"></div>
        </div>
      </div>
    </div>
  );
};

