const NorthStarCard: React.FC<{ label: string; description: string }> = ({ label, description }) => {
  const containerRef = useRef<HTMLDivElement>(null);
  const [mousePos, setMousePos] = useState({ x: 0, y: 0 });
  const [isHovered, setIsHovered] = useState(false);

  const handleMouseMove = (e: React.MouseEvent) => {
    if (!containerRef.current) return;
    const rect = containerRef.current.getBoundingClientRect();
    setMousePos({ x: e.clientX - rect.left, y: e.clientY - rect.top });
  };

  return (
    <div 
      ref={containerRef}
      onMouseMove={handleMouseMove}
      onMouseEnter={() => setIsHovered(true)}
      onMouseLeave={() => setIsHovered(false)}
      className="group relative w-full max-w-2xl mx-auto p-12 rounded-[3rem] border border-white/20 transition-all duration-[1000ms] hover:border-orange-500/40 shadow-[0_32px_64px_-16px_rgba(0,0,0,0.5)] overflow-hidden cursor-default perspective-2000 bg-white/[0.05] backdrop-blur-[80px]"
      style={{
        transform: isHovered 
          ? `perspective(2000px) rotateX(${(mousePos.y / 200 - 1) * -2}deg) rotateY(${(mousePos.x / 350 - 1) * 2}deg)` 
          : 'none'
      }}
    >
      {/* Subtle Inner Glow */}
      <div className="absolute inset-0 bg-gradient-to-br from-white/[0.08] to-transparent pointer-events-none"></div>

      <div className="relative z-10 flex flex-col items-center text-center">
        <div className="flex items-center gap-3 mb-8 opacity-60 group-hover:opacity-100 transition-opacity duration-700">
           <div className="w-2 h-2 rounded-full bg-orange-500 shadow-[0_0_12px_rgba(249,115,22,1)]"></div>
           <span className="text-[10px] font-bold text-white tracking-[0.4em] uppercase font-sans">Strategic impact</span>
