  const [mousePos, setMousePos] = useState({ x: 0, y: 0 });
  const [isHovered, setIsHovered] = useState(false);

  const handleMouseMove = (e: React.MouseEvent) => {
    if (!containerRef.current) return;
    const rect = containerRef.current.getBoundingClientRect();
    setMousePos({ x: e.clientX - rect.left, y: e.clientY - rect.top });
  };

  return (
    <div 
      ref={containerRef}
      onMouseMove={handleMouseMove}
      onMouseEnter={() => setIsHovered(true)}
      onMouseLeave={() => setIsHovered(false)}
      className="group relative w-full max-w-xl mx-auto p-10 rounded-[2.5rem] border border-white/20 transition-all duration-[1000ms] hover:border-orange-500/40 shadow-2xl overflow-hidden cursor-default perspective-1000 bg-white/[0.04] backdrop-blur-[80px]"
      style={{
        transform: isHovered 
          ? `perspective(1000px) rotateX(${(mousePos.y / 200 - 1) * -2}deg) rotateY(${(mousePos.x / 300 - 1) * 2}deg)` 
          : 'none'
      }}
    >
      <div className="absolute top-0 left-0 right-0 h-[1px] bg-gradient-to-r from-transparent via-white/30 to-transparent pointer-events-none"></div>

