    { id: 0, phase: "Phase 01", title: "Refining Outcomes", content: nextSteps.split('. ')[0] + '.' || "Optimizing interaction frameworks.", icon: "M13 10V3L4 14h7v7l9-11h-7z" },
    { id: 1, phase: "Phase 02", title: "Scaling System", content: nextSteps.split('. ')[1] + '.' || "Broadening the design architecture.", icon: "M4 8V4m0 0h4M4 4l5 5m11-1V4m0 0h-4m4 0l-5 5M4 16v4m0 0h4m-4 0l5-5m11 5l-5-5m5 5v-4m0 4h-4" },
    { id: 2, phase: "Phase 03", title: "Future Vision", content: nextSteps.split('. ').slice(2).join('. ') || "Pioneering the next gen features.", icon: "M9.663 17h4.673M12 3v1" }
  ];

  const handleStepChange = (idx: number) => {
    if (idx === activeStep) return;
    setIsRotating(true);
    setActiveStep(idx);
    setTimeout(() => setIsRotating(false), 800);
  };

  return (
    <div className="w-full max-w-4xl mx-auto mt-20 relative flex flex-col lg:flex-row items-center justify-center gap-12 lg:gap-16 px-6 reveal">
      <div className="relative w-[240px] h-[240px] shrink-0">
        <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-20 h-20 glass rounded-full border border-white/20 flex flex-col items-center justify-center z-20 bg-black/80 shadow-xl backdrop-blur-[80px]">
