           <div className="flex gap-1.5 mt-1.5">
             {steps.map((_, i) => (
               <div key={i} className={`w-1 h-1 rounded-full ${i === activeStep ? 'bg-orange-500 scale-125 shadow-[0_0_8px_rgba(249,115,22,1)]' : 'bg-white/10'} transition-all duration-700`}></div>
             ))}
           </div>
        </div>
        <div className="absolute inset-0 rounded-full border border-white/[0.05] animate-spin-slow"></div>
        {steps.map((step, idx) => {
          const angle = (idx * (360 / steps.length)) - 90;
          const rotationAngle = angle + (activeStep * -120);
          return (
            <div key={step.id} className="absolute top-1/2 left-1/2 w-full h-full transition-transform duration-[1000ms] cubic-bezier(0.16, 1, 0.3, 1) z-30 pointer-events-none" style={{ transform: `translate3d(-50%, -50%, 0) rotate(${rotationAngle}deg)` }}>
              <button onClick={() => handleStepChange(idx)} className={`absolute top-0 left-1/2 -translate-x-1/2 -translate-y-1/2 pointer-events-auto transition-all duration-700 ${activeStep === idx ? 'scale-110' : 'scale-75 opacity-30 hover:opacity-100'}`}>
                <div className="flex flex-col items-center gap-1.5" style={{ transform: `rotate(${-rotationAngle}deg)` }}>
                  <div className={`w-12 h-12 rounded-2xl border flex items-center justify-center relative transition-all duration-700 bg-white/[0.05] backdrop-blur-[60px] ${activeStep === idx ? 'border-orange-500/60 shadow-[0_0_30px_rgba(249,115,22,0.3)]' : 'border-white/20'}`}>
                    <svg className={`w-5 h-5 ${activeStep === idx ? 'text-orange-500' : 'text-white/60'}`} fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1.5} d={step.icon} /></svg>
