              </button>
            </div>
          );
        })}
      </div>
      <div className="flex-1 w-full relative">
        <div className={`p-10 md:p-12 rounded-[3rem] border border-white/20 relative overflow-hidden transition-all duration-700 shadow-2xl min-h-[300px] flex flex-col justify-center bg-white/[0.02] backdrop-blur-[120px] ${isRotating ? 'opacity-0 translate-y-4 blur-xl scale-98' : 'opacity-100 translate-y-0 blur-none scale-100'}`}>
          <div className="relative z-10 text-left">
            <div className="flex items-center gap-4 mb-6">
              <span className="text-[10px] font-black tracking-[0.4em] text-orange-500 uppercase font-sans">{steps[activeStep].phase}</span>
              <div className="h-[1px] flex-1 bg-white/10"></div>
            </div>
            <h3 className="text-2xl md:text-3xl font-bold tracking-tighter text-white mb-6 font-display leading-tight">{steps[activeStep].title}</h3>
            <p className="text-base md:text-lg text-white/70 font-light italic leading-relaxed tracking-tight">"{steps[activeStep].content}"</p>
          </div>
          <div className="absolute top-0 left-0 right-0 h-[1px] bg-gradient-to-r from-transparent via-white/15 to-transparent"></div>
        </div>
      </div>
    </div>
  );
};

