const NorthStarCard: React.FC<{ label: string; description: string }> = ({ label, description }) => {
  const containerRef = useRef<HTMLDivElement>(null);
  const [mousePos, setMousePos] = useState({ x: 0, y: 0 });
  const [isHovered, setIsHovered] = useState(false);

  const handleMouseMove = (e: React.MouseEvent) => {
    if (!containerRef.current) return;
    const rect = containerRef.current.getBoundingClientRect();
    setMousePos({ x: e.clientX - rect.left, y: e.clientY - rect.top });
  };

  return (
    <div 
      ref={containerRef}
      onMouseMove={handleMouseMove}
      onMouseEnter={() => setIsHovered(true)}
      onMouseLeave={() => setIsHovered(false)}
      className="group relative w-full max-w-2xl mx-auto glass p-12 rounded-[2.5rem] border border-white/20 transition-all duration-[800ms] hover:border-orange-500/50 shadow-2xl overflow-hidden cursor-default perspective-1000 bg-white/[0.05] backdrop-blur-[32px]"
      style={{
        transform: isHovered 
          ? `perspective(1000px) rotateX(${(mousePos.y / 200 - 1) * -1.5}deg) rotateY(${(mousePos.x / 350 - 1) * 1.5}deg)` 
          : 'none'
      }}
    >
      <div className="relative z-10 flex flex-col items-center text-center">
        <div className="flex items-center gap-2.5 mb-8 opacity-60 group-hover:opacity-100 transition-opacity duration-700">
           <div className="w-1.5 h-1.5 rounded-full bg-orange-500 shadow-[0_0_8px_rgba(249,115,22,0.8)]"></div>
           <span className="text-[10px] font-bold text-white tracking-[0.3em] uppercase font-sans">Strategic impact</span>
        </div>
        <h3 className="text-3xl md:text-4xl font-bold text-white mb-6 tracking-tight leading-tight font-display">
          {label}
        </h3>
        <p className="text-lg md:text-xl text-white/80 font-light italic leading-relaxed group-hover:text-white transition-all duration-700">
          "{description}"
        </p>
      </div>
    </div>
  );
};

const EvolutionHub: React.FC<{ nextSteps: string }> = ({ nextSteps }) => {
  const [activeStep, setActiveStep] = useState(0);
  const [isRotating, setIsRotating] = useState(false);

  const steps = [
    {
      id: 0,
      phase: "Phase 01",
      title: "Outcome Optimization",
      label: "Iterative Improvement",
      content: nextSteps.split('. ')[0] + '.' || "Analyzing user engagement data to refine core interaction loops.",
      icon: <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1.5} d="M13 10V3L4 14h7v7l9-11h-7z" /></svg>
    },
    {
      id: 1,
      phase: "Phase 02",
      title: "Strategic Scaling",
      label: "Experience Expansion",
      content: nextSteps.split('. ')[1] + '.' || "Evolving the design system architecture to support growth.",
      icon: <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1.5} d="M4 8V4m0 0h4M4 4l5 5m11-1V4m0 0h-4m4 0l-5 5M4 16v4m0 0h4m-4 0l5-5m11 5l-5-5m5 5v-4m0 4h-4" /></svg>
    },
    {
      id: 2,
      phase: "Phase 03",
      title: "Predictive Value",
      label: "Innovation Roadmap",
      content: nextSteps.split('. ').slice(2).join('. ') || "Leveraging patterns to anticipate user needs through high-fidelity experiences.",
      icon: <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1.5} d="M9.663 17h4.673M12 3v1m6.364 1.636l-.707.707M21 12h-1M4 12H3m3.343-5.657l-.707-.707m2.828 9.9a5 5 0 117.072 0l-.548.547A3.374 3.374 0 0012 18.75c-1.03 0-1.9-.4-2.593-.579a5.356 5.356 0 01-.84-.371z" /></svg>
    }
  ];

  const handleStepChange = (idx: number) => {
    if (idx === activeStep) return;
    setIsRotating(true);
    setActiveStep(idx);
    setTimeout(() => setIsRotating(false), 600);
  };

  return (
    <div className="w-full max-w-5xl mx-auto mt-2 relative flex flex-col lg:flex-row items-center justify-center gap-12 lg:gap-20 px-6">
      <div className="relative w-[280px] h-[280px] md:w-[320px] md:h-[320px] shrink-0">
        <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-24 h-24 md:w-28 md:h-28 glass rounded-full border border-white/20 flex flex-col items-center justify-center z-20 bg-black/80 shadow-2xl backdrop-blur-3xl">
           <span className="text-[10px] font-black tracking-[0.2em] text-white/60 mb-1 uppercase font-sans">Evolve</span>
           <div className="flex gap-1.5 mt-2">
             {steps.map((_, i) => (
               <div key={i} className={`w-1.5 h-1.5 rounded-full ${i === activeStep ? 'bg-orange-500 scale-125 shadow-[0_0_10px_rgba(249,115,22,0.6)]' : 'bg-white/20'} transition-all duration-500`}></div>
             ))}
           </div>
        </div>
        <div className="absolute inset-0 rounded-full border border-white/[0.08] animate-spin-slow"></div>
        {steps.map((step, idx) => {
          const angle = (idx * (360 / steps.length)) - 90;
          const isActive = activeStep === idx;
          const rotationAngle = angle + (activeStep * -120);
          return (
            <div key={step.id} className="absolute top-1/2 left-1/2 w-full h-full transition-transform duration-[800ms] ease-[cubic-bezier(0.2,1,0.3,1)] z-30 pointer-events-none" style={{ transform: `translate3d(-50%, -50%, 0) rotate(${rotationAngle}deg)` }}>
              <button onClick={() => handleStepChange(idx)} className={`absolute top-0 left-1/2 -translate-x-1/2 -translate-y-1/2 pointer-events-auto transition-all duration-700 ${isActive ? 'scale-110' : 'scale-90 opacity-60 hover:opacity-100 hover:scale-100'}`}>
                <div className="flex flex-col items-center gap-2" style={{ transform: `rotate(${-rotationAngle}deg)` }}>
                  <div className={`w-12 h-12 glass rounded-2xl border flex items-center justify-center relative transition-all duration-500 bg-black/80 backdrop-blur-2xl ${isActive ? 'border-orange-500/60 shadow-[0_0_20px_rgba(249,115,22,0.2)]' : 'border-white/20 hover:border-white/40'}`}>
                    <div className={`${isActive ? 'text-orange-500' : 'text-white/60'}`}>{step.icon}</div>
                  </div>
                </div>
              </button>
            </div>
          );
        })}
      </div>
      <div className="flex-1 w-full relative">
        <div className={`glass p-8 md:p-10 rounded-[2.5rem] border border-white/20 relative overflow-hidden transition-all duration-500 shadow-2xl min-h-[300px] flex flex-col justify-center bg-white/[0.05] backdrop-blur-[40px] ${isRotating ? 'opacity-0 translate-y-4 blur-xl' : 'opacity-100 translate-y-0 blur-none'}`}>
          <div className="relative z-10">
            <div className="flex items-center gap-3 mb-6">
              <span className="text-[11px] font-black tracking-[0.2em] text-orange-500 uppercase font-sans">{steps[activeStep].phase}</span>
              <div className="h-[1px] flex-1 bg-white/[0.15]"></div>
            </div>
            <h3 className="text-2xl md:text-3xl font-bold tracking-tight text-white mb-6 font-display">{steps[activeStep].title}</h3>
            <p className="text-base md:text-lg text-white/80 font-light italic leading-relaxed tracking-tight">"{steps[activeStep].content}"</p>
          </div>
        </div>
      </div>
    </div>
  );
};

