const ProjectDetailView: React.FC<{ 
  project: Project; 
  projects: Project[];
  onBack: () => void; 
  onNext: () => void 
}> = ({ project, projects, onBack, onNext }) => {
  const [activeSection, setActiveSection] = useState('hero');
  const [activeProcessIdx, setActiveProcessIdx] = useState(0);
  const [isNavVisible, setIsNavVisible] = useState(false);

  const sections = [
    { id: 'hero', label: 'Intro' },
    { id: 'overview', label: 'Summary' },
    { id: 'problem', label: 'Challenge' },
    { id: 'research', label: 'Research' },
    { id: 'solution', label: 'Solution' },
    { id: 'process', label: 'Execution' },
    { id: 'design', label: 'Design' },
    { id: 'impact', label: 'Results' },
    { id: 'continuity', label: 'Reflection' },
  ];

  useEffect(() => {
    const handleScroll = () => {
      const buffer = 150;
      let currentSectionId = sections[0].id;
      for (const section of sections) {
        const element = document.getElementById(section.id);
        if (element) {
          const rect = element.getBoundingClientRect();
          if (rect.top <= buffer && rect.bottom > buffer) {
            currentSectionId = section.id;
          }
        }
      }
      setActiveSection(currentSectionId);
      setIsNavVisible(window.scrollY > 300);
    };
    window.addEventListener("scroll", handleScroll, { passive: true });
    handleScroll();
    return () => window.removeEventListener("scroll", handleScroll);
  }, [sections]);

  const scrollToSection = (id: string) => {
    document.getElementById(id)?.scrollIntoView({ behavior: 'smooth', block: 'start' });
  };

  const nextProject = projects[(projects.findIndex(p => p.id === project.id) + 1) % projects.length];
  const insights = [
    { text: project.researchInsights, icon: <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1.5} d="M9 20l-5.447-2.724A2 2 0 013 15.487V6a2 2 0 011.137-1.81l5.447-2.724a2 2 0 011.83 0L15 4.147m-6 15.853V4.147m6 15.853l5.447-2.724A2 2 0 0021 15.487V6" /></svg>},
    { text: project.researchInsight2, icon: <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1.5} d="M13.828 10.172a4 4 0 00-5.656 0l-4 4a4 4 0 105.656 5.656l1.102-1.101m-.758-4.899a4 4 0 005.656 0l4-4" /></svg>},
    { text: project.researchInsight3, icon: <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1.5} d="M12 15v2m-6 4h12a2 2 0 002-2v-6a2 2 0 00-2-2H6a2 2 0 00-2 2v6" /></svg>}
  ].filter(i => i.text);

  return (
    <div className="bg-transparent min-h-screen relative z-10">
      <nav className={`fixed right-8 top-0 bottom-0 w-12 z-[100] hidden lg:flex flex-col items-center justify-center transition-all duration-700 ${isNavVisible ? 'opacity-100 translate-x-0' : 'opacity-0 translate-x-12 pointer-events-none'}`}>
        <div className="flex flex-col gap-6 items-center p-4 rounded-full bg-black/40 backdrop-blur-md border border-white/10 shadow-2xl">
