const ProjectDetailView: React.FC<{ 
  project: Project; 
  projects: Project[];
  onBack: () => void; 
  onNext: () => void 
}> = ({ project, projects, onBack, onNext }) => {
  const [activeSection, setActiveSection] = useState('hero');
  const [activeProcessIdx, setActiveProcessIdx] = useState(0);
  const [isNavVisible, setIsNavVisible] = useState(false);

  const sections = [
    { id: 'hero', label: 'Intro' },
    { id: 'overview', label: 'Summary' },
    { id: 'problem', label: 'Challenge' },
    { id: 'research', label: 'Research' },
    { id: 'solution', label: 'Solution' },
    { id: 'process', label: 'Execution' },
    { id: 'design', label: 'Design' },
    { id: 'impact', label: 'Results' },
    { id: 'continuity', label: 'Reflection' },
  ];

  useEffect(() => {
    const handleScroll = () => {
      const buffer = 150;
      let currentSectionId = sections[0].id;
      for (const section of sections) {
        const element = document.getElementById(section.id);
        if (element) {
          const rect = element.getBoundingClientRect();
          if (rect.top <= buffer && rect.bottom > buffer) {
            currentSectionId = section.id;
          }
        }
      }
      setActiveSection(currentSectionId);
      setIsNavVisible(window.scrollY > 300);
    };
    window.addEventListener("scroll", handleScroll, { passive: true });
    handleScroll();
    return () => window.removeEventListener("scroll", handleScroll);
  }, [sections]);

  const scrollToSection = (id: string) => {
    document.getElementById(id)?.scrollIntoView({ behavior: 'smooth', block: 'start' });
  };

  const nextProject = projects[(projects.findIndex(p => p.id === project.id) + 1) % projects.length];
