const App: React.FC = () => {
  const [currentView, setCurrentView] = useState<View>('work');
  const [selectedProject, setSelectedProject] = useState<Project | null>(null);
  const [isLoading, setIsLoading] = useState(true);
  const [mousePos, setMousePos] = useState({ x: 0, y: 0 });

  const isDetailView = currentView === 'project-detail';

  useEffect(() => {
    const handleMouseMove = (e: MouseEvent) => setMousePos({ x: e.clientX, y: e.clientY });
    window.addEventListener('mousemove', handleMouseMove);
    return () => window.removeEventListener('mousemove', handleMouseMove);
  }, []);

  useEffect(() => {
    const revealOptions = { threshold: 0.1, rootMargin: '0px 0px -100px 0px' };
    const revealObserver = new IntersectionObserver((entries) => {
      entries.forEach(entry => {
        if (entry.isIntersecting) {
          const target = entry.target as HTMLElement;
          setTimeout(() => target.classList.add('reveal-visible'), parseInt(target.dataset.delay || '0'));
          revealObserver.unobserve(target);
        }
      });
    }, revealOptions);
    document.querySelectorAll('.reveal').forEach(el => revealObserver.observe(el));
    if (!isLoading) window.scrollTo(0, 0);
    return () => revealObserver.disconnect();
  }, [currentView, isLoading, selectedProject]);

  const handleProjectClick = (project: Project) => {
    setSelectedProject(project);
    setCurrentView('project-detail');
  };

  const renderView = () => {
    const activeProject = selectedProject ? PROJECTS.find(p => p.id === selectedProject.id) : null;
    switch (currentView) {
      case 'case-studies': return <CaseStudiesView projects={PROJECTS} onSelectProject={handleProjectClick} />;
      case 'info': return <InfoView />;
      case 'project-detail': return activeProject ? (
        <ProjectDetailView 
          project={activeProject} 
          projects={PROJECTS}
          onBack={() => { setCurrentView('work'); setSelectedProject(null); }} 
          onNext={() => {
            const idx = PROJECTS.findIndex(p => p.id === activeProject.id);
            setSelectedProject(PROJECTS[(idx + 1) % PROJECTS.length]);
            window.scrollTo({ top: 0, behavior: 'smooth' });
          }}
        />
      ) : <WorkView projects={PROJECTS} onProjectClick={handleProjectClick} />;
      default: return <WorkView projects={PROJECTS} onProjectClick={handleProjectClick} />;
    }
  };

  return (
