           </div>
        </div>

        <div className="absolute inset-0 rounded-full border border-white/[0.05] animate-spin-slow"></div>
        <div className="absolute inset-8 rounded-full border border-orange-500/[0.05] animate-spin-slow" style={{ animationDirection: 'reverse' }}></div>

        {steps.map((step, idx) => {
          const angle = (idx * (360 / steps.length)) - 90;
          const isActive = activeStep === idx;
          const rotationAngle = angle + (activeStep * -120);
          return (
            <div key={step.id} className="absolute top-1/2 left-1/2 w-full h-full transition-transform duration-[1100ms] cubic-bezier(0.16, 1, 0.3, 1) z-30 pointer-events-none" style={{ transform: `translate3d(-50%, -50%, 0) rotate(${rotationAngle}deg)` }}>
              <button 
                onClick={() => handleStepChange(idx)} 
                className={`absolute top-0 left-1/2 -translate-x-1/2 -translate-y-1/2 pointer-events-auto transition-all duration-700 ${isActive ? 'scale-125' : 'scale-90 opacity-70 hover:opacity-100 hover:scale-100'}`}
              >
                <div className="flex flex-col items-center gap-2" style={{ transform: `rotate(${-rotationAngle}deg)` }}>
                  <div className={`w-14 h-14 md:w-16 md:h-16 glass-panel rounded-2xl border flex items-center justify-center relative transition-all duration-700 bg-black/80 backdrop-blur-2xl ${isActive ? 'border-orange-500 shadow-[0_0_30px_rgba(249,115,22,0.3)]' : 'border-white/30 hover:border-orange-500/50'}`}>
                    <div className={`${isActive ? 'text-orange-500' : 'text-white/90'} transition-colors duration-500`}>
                      {React.cloneElement(step.icon as React.ReactElement, { className: isActive ? 'w-7 h-7' : 'w-5 h-5' })}
                    </div>
                  </div>
                </div>
              </button>
            </div>
          );
        })}
      </div>

      <div className="flex-1 w-full relative">
        <div className={`glass-panel p-8 md:p-14 rounded-[3rem] border border-white/10 relative overflow-hidden transition-all duration-700 shadow-2xl min-h-[380px] flex flex-col justify-center bg-white/[0.04] backdrop-blur-[80px] ${isRotating ? 'opacity-0 translate-y-8 blur-2xl scale-95' : 'opacity-100 translate-y-0 blur-none scale-100'}`}>
          <div className="relative z-10">
            <div className="flex items-center gap-4 mb-8">
              <div className="w-1.5 h-1.5 rounded-full bg-orange-500 shadow-[0_0_12px_rgba(249,115,22,1)]"></div>
              <span className="text-[12px] font-black tracking-[0.5em] text-orange-500 uppercase font-sans">{steps[activeStep].phase}</span>
              <div className="h-[1px] flex-1 bg-gradient-to-r from-white/15 to-transparent"></div>
            </div>
            <h3 className="text-3xl md:text-5xl font-bold tracking-tighter text-white mb-8 font-display leading-[1]">{steps[activeStep].title}</h3>
            <p className="text-lg md:text-xl text-white/80 font-light italic leading-relaxed tracking-tight border-l-2 border-orange-500/20 pl-8">
              "{steps[activeStep].content}"
            </p>
          </div>
        </div>
      </div>
    </div>
  );
};

