                <div className="flex items-center gap-4 mb-8">
                   <div className="w-12 h-12 rounded-2xl glass border border-orange-500/40 flex items-center justify-center bg-orange-500/10 shadow-[0_0_20px_rgba(249,115,22,0.2)]">
                      <span className="text-xl font-bold text-orange-500 font-sans">0{idx + 1}</span>
