import React, { useEffect, useState, useRef } from 'react';
import { View } from '../types';

interface CustomCursorProps {
  currentView?: View;
}

const CustomCursor: React.FC<CustomCursorProps> = ({ currentView }) => {
  const dotRef = useRef<HTMLDivElement>(null);
  const coreRef = useRef<HTMLDivElement>(null);
  const ringRef = useRef<HTMLDivElement>(null);
  const [hoverType, setHoverType] = useState<'none' | 'ui' | 'project'>('none');
  const [isVisible, setIsVisible] = useState(false);

  useEffect(() => {
    const onMouseMove = (e: MouseEvent) => {
      if (!isVisible) setIsVisible(true);

      const { clientX, clientY } = e;

      if (dotRef.current) {
        dotRef.current.style.transform = `translate3d(${clientX}px, ${clientY}px, 0)`;
      }

      if (coreRef.current) {
        coreRef.current.style.transform = `translate3d(${clientX}px, ${clientY}px, 0)`;
      }

      if (ringRef.current) {
        // Subtle inertia for the outer ring
        ringRef.current.style.transform = `translate3d(${clientX}px, ${clientY}px, 0)`;
      }

      // Detect interaction type
      const target = e.target as HTMLElement;
      if (target.closest('[data-cursor="project"]')) {
        setHoverType('project');
      } else if (target.closest('button, a, .cursor-pointer, input')) {
        setHoverType('ui');
      } else {
        setHoverType('none');
      }
    };

    const onMouseLeave = () => setIsVisible(false);
    const onMouseEnter = () => setIsVisible(true);

    window.addEventListener('mousemove', onMouseMove);
    document.addEventListener('mouseleave', onMouseLeave);
    document.addEventListener('mouseenter', onMouseEnter);

    return () => {
      window.removeEventListener('mousemove', onMouseMove);
      document.removeEventListener('mouseleave', onMouseLeave);
      document.removeEventListener('mouseenter', onMouseEnter);
    };
  }, [isVisible]);

  const getRingStyles = () => {
    switch (hoverType) {
      case 'project':
        return 'w-28 h-28 -ml-14 -mt-14 scale-100 bg-orange-500/10 border-orange-500/60 shadow-[0_0_40px_rgba(249,115,22,0.3)]';
      case 'ui':
        return 'w-18 h-18 -ml-9 -mt-9 bg-white/5 border-white/50 scale-100 shadow-[0_0_20px_rgba(255,255,255,0.1)]';
      default:
        return 'w-10 h-10 -ml-5 -mt-5 bg-transparent border-white/20 scale-100';
    }
  };

  return (
    <div className={`fixed inset-0 pointer-events-none z-[9999] transition-opacity duration-500 ${isVisible ? 'opacity-100' : 'opacity-0'} hidden md:block`}>
      {/* Precision Dot */}
      <div 
        ref={dotRef}
        className="fixed top-0 left-0 w-1.5 h-1.5 bg-white rounded-full -ml-0.75 -mt-0.75 will-change-transform z-20"
      />

      {/* Dynamic Orange Core */}
      <div 
        ref={coreRef}
        className={`fixed top-0 left-0 w-3 h-3 bg-orange-500 rounded-full -ml-1.5 -mt-1.5 will-change-transform z-10 transition-all duration-500 blur-[2px] ${hoverType !== 'none' ? 'scale-[2.5] opacity-100' : 'scale-0 opacity-0'}`}
      />

      {/* Fluid Interactive Ring */}
      <div 
        ref={ringRef}
        className={`fixed top-0 left-0 border rounded-full transition-all duration-[600ms] cubic-bezier(0.23, 1, 0.32, 1) will-change-transform backdrop-blur-[4px] flex items-center justify-center overflow-hidden ${getRingStyles()}`}
      >
        <span className={`text-[10px] font-black tracking-[0.4em] text-orange-500 transition-all duration-500 translate-y-0 ${hoverType === 'project' ? 'opacity-100 translate-y-0' : 'opacity-0 translate-y-4'}`}>
          VIEW
        </span>
      </div>
    </div>
  );
};

export default CustomCursor;

