const ScrollProgress: React.FC = () => {
  const [scroll, setScroll] = useState(0);

  useEffect(() => {
    const handleScroll = () => {
      const winScroll = document.documentElement.scrollTop;
      const height = document.documentElement.scrollHeight - document.documentElement.clientHeight;
      const scrolled = (winScroll / height) * 100;
      setScroll(scrolled);
    };
    window.addEventListener("scroll", handleScroll, { passive: true });
    return () => window.removeEventListener("scroll", handleScroll);
  }, []);

  return (
    <div className="fixed top-0 left-0 w-full h-[2px] z-[110] bg-white/[0.05]">
      <div 
        className="h-full bg-orange-500 shadow-[0_0_15px_rgba(249,115,22,1)] transition-all duration-300 ease-out"
        style={{ width: `${scroll}%` }}
      />
    </div>
  );
};

const NorthStarCard: React.FC<{ label: string; description: string }> = ({ label, description }) => {
  const containerRef = useRef<HTMLDivElement>(null);
  const [mousePos, setMousePos] = useState({ x: 0, y: 0 });
  const [isHovered, setIsHovered] = useState(false);

  const handleMouseMove = (e: React.MouseEvent) => {
    if (!containerRef.current) return;
    const rect = containerRef.current.getBoundingClientRect();
    setMousePos({ x: e.clientX - rect.left, y: e.clientY - rect.top });
  };

  return (
    <div 
      ref={containerRef}
      onMouseMove={handleMouseMove}
      onMouseEnter={() => setIsHovered(true)}
      onMouseLeave={() => setIsHovered(false)}
      className="group relative w-full max-w-2xl mx-auto glass-panel p-12 rounded-[2.5rem] border border-white/20 transition-all duration-[800ms] hover:border-orange-500/50 hover:shadow-[0_40px_80px_-20px_rgba(249,115,22,0.15)] hover:-translate-y-2 overflow-hidden cursor-default perspective-1000"
      style={{
        transform: isHovered 
          ? `perspective(1000px) rotateX(${(mousePos.y / 200 - 1) * -2}deg) rotateY(${(mousePos.x / 350 - 1) * 2}deg)` 
          : 'none'
      }}
    >
      <div className="relative z-10 flex flex-col items-center text-center">
        <div className="flex items-center gap-2.5 mb-8 opacity-60 group-hover:opacity-100 transition-opacity duration-700">
           <div className="w-1.5 h-1.5 rounded-full bg-orange-500 shadow-[0_0_10px_rgba(249,115,22,0.8)]"></div>
           <span className="text-[10px] font-black text-white tracking-[0.4em] uppercase font-sans">North Star Outcome</span>
        </div>
        <h3 className="text-3xl md:text-5xl font-bold text-white mb-6 tracking-tighter leading-tight font-display">
          {label}
        </h3>
        <p className="text-lg md:text-2xl text-white/70 font-light italic leading-relaxed group-hover:text-white transition-all duration-700 max-w-lg">
          "{description}"
        </p>
      </div>
    </div>
  );
};

